export function buildUserPrompt(payloadJson: string): string {
  return [
    "Generate O1DMatch outreach outputs for the selected company and contact.",
    "",
    "Use the JSON payload below as the only factual source. Do not invent facts.",
    "If information is missing, say what is missing in missing_information and omit factual claims that require that missing information.",
    "",
    "Payload:",
    payloadJson,
  ].join("\n");
}
